const text = $json.textPlain || "";
const subject = $json.textSubject || "";

// 1. Extract Bucket Name
const bucketMatch = text.match(/bucket[:\s]*([a-z0-9-_.]+)/i) || subject.match(/bucket[:\s]*([a-z0-9-_.]+)/i);
const bucketName = bucketMatch ? bucketMatch[1] : null;

// 2. Extract Object Name
const objectMatch = text.match(/object[:\s]*([^\s]+)/i) || subject.match(/object[:\s]*([^\s]+)/i);
const objectName = objectMatch ? objectMatch[1] : null;

// 3. Determine Task Type
let task_type = "";
if (/create object|upload/i.test(text) || /create object|upload/i.test(subject)) task_type = "create_object";
else if (/delete object/i.test(text) || /delete object/i.test(subject)) task_type = "delete_object";
else if (/list objects/i.test(text) || /list objects/i.test(subject)) task_type = "list_objects";
else if (/get object/i.test(text) || /get object/i.test(subject)) task_type = "get_object";
else if (/update object/i.test(text) || /update object/i.test(subject)) task_type = "update_object";

return [{ json: { bucketName, objectName, task_type } }];

const taskType = $json.task_type || "";
const bucketName = $json.bucketName || "";
const objectName = $json.objectName || "";
const errorMsg = $json.error || "";
const status = $json.status || "success";

// If there is an error message, treat as failure
const isFailure = !!errorMsg;

const taskMap = {
  create_object: "Create GCS Object",
  delete_object: "Delete GCS Object",
  get_object: "Get GCS Object",
  list_objects: "List GCS Objects",
  update_object: "Update GCS Object"
};

let subject = "";
let message = "";

if (isFailure) {
    subject = `❌ Failure - ${taskMap[taskType] || "GCS Task"}`;
    message = `❌ ${taskMap[taskType] || "Task"} failed.\n`;
    if (bucketName) message += `Bucket: ${bucketName}\n`;
    if (objectName) message += `Object: ${objectName}\n`;
    message += `Error: ${errorMsg}\n`;
} else {
    subject = `✅ Success - ${taskMap[taskType] || "GCS Task"}`;
    message = `✅ ${taskMap[taskType] || "Task"} completed successfully.\n`;
    if (bucketName) message += `Bucket: ${bucketName}\n`;
    if (objectName) message += `Object: ${objectName}\n`;

    // Handle List Objects
    if (taskType === "list_objects") {
        const items = $input.all().map(i => i.json.name).join("\n");
        if (items.length > 0) {
             message += `\nObjects Found:\n${items}`;
        } else {
             message += "\nNo objects found.";
        }
    }
}

return { json: { subject, body: message } };
